func (s *Service) GetArtifactMetadata(ctx context.Context, artifactID string, allowedTypes map[string]struct{}) (types.ArtifactMetadata, error) {
	principal := auth.PrincipalFromContext(ctx)
	jobs, err := s.store.ListJobs(ctx)
	if err != nil {
		return types.ArtifactMetadata{}, err
	}
	sort.SliceStable(jobs, func(i, j int) bool {
		return jobs[i].SubmittedAt.After(jobs[j].SubmittedAt)
	})
	for _, job := range jobs {
		if err := authz.AuthorizeJobAccess(principal, job); err != nil {
			continue
		}
		// Metadata contains no artifact path or content. Keep it available for
		// authorized jobs while still enforcing inspection's full-trace gate.
		eligible := filterJobArtifactsForRelease(job, job.Artifacts)
		for _, artifact := range eligible {
			if artifact.ArtifactID != artifactID {
				continue
			}
			if len(allowedTypes) > 0 {
				if _, ok := allowedTypes[artifact.ArtifactType]; !ok {
					continue
				}
			}
			schemaName := ""
			if job.Result != nil {
				schemaName = job.Result.SchemaName
			}
			return types.ArtifactMetadata{
				ArtifactID:     artifact.ArtifactID,
				ArtifactType:   artifact.ArtifactType,
				Classification: artifact.Classification,
				ContentHash:    artifact.ContentHash,
				SourceJobID:    job.ID,
				SourceTaskType: job.TaskType,
				SourceSchema:   schemaName,
				SubmittedBy:    job.SubmittedBy,
				CreatedAt:      job.CreatedAt.Format(time.RFC3339),
			}, nil
		}
	}
	return types.ArtifactMetadata{}, store.ErrNotFound
}

func validateEvidencePackShape(payload map[string]any, requireQuery bool) error {
	if requireQuery {
		if _, ok := payload["query"].(string); !ok {
			return fmt.Errorf("payload.query must be a string")
		}
	}
	if retrieval, exists := payload["retrieval"]; exists {
		if _, ok := retrieval.(map[string]any); !ok {
			return fmt.Errorf("payload.retrieval must be an object")
		}
	}
	if retrievalPlan, exists := payload["retrieval_plan"]; exists {
		if _, ok := retrievalPlan.(map[string]any); !ok {
			return fmt.Errorf("payload.retrieval_plan must be an object")
		}
	}
	if retrievalTrace, exists := payload["retrieval_trace"]; exists {
		if _, ok := retrievalTrace.(map[string]any); !ok {
			return fmt.Errorf("payload.retrieval_trace must be an object")
		}
	}
	if evidence, exists := payload["evidence"]; exists {
		if _, ok := evidence.([]any); !ok {
			return fmt.Errorf("payload.evidence must be an array")
		}
	}
	if budget, exists := payload["budget"]; exists {
		if _, ok := budget.(map[string]any); !ok {
			return fmt.Errorf("payload.budget must be an object")
		}
	}
	return nil
}

func (s *Service) buildParallelReducerRequest(req types.SubmitParallelJobsRequest, rootJobID string, childJobIDs, childBackendRunIDs []string) types.SubmitJobRequest {
	orderedChildJobIDs := compactNonEmptyStrings(childJobIDs)
	reducerTaskType := firstNonEmpty(req.Reducer.TaskType, req.TaskType)
	reducerSchema := req.Reducer.OutputSchema
	if reducerSchema.Name == "" {
		reducerSchema = req.OutputSchema
	}
	reducerProfile := req.ExecutionProfile
	if req.Reducer.ExecutionProfile != (types.ExecutionProfile{}) {
		reducerProfile = req.Reducer.ExecutionProfile
	}
	reducerConstraints := req.Constraints
	if req.Reducer.Constraints != (types.Constraints{}) {
		reducerConstraints = req.Reducer.Constraints
	}
	reducerTaskParams := cloneTaskParams(req.TaskParams)
	for k, v := range req.Reducer.TaskParams {
		reducerTaskParams[k] = v
	}
	reducerTaskParams[taskParamChildJobIDs] = append([]string(nil), orderedChildJobIDs...)
	reducerTaskParams[taskParamRootJobID] = rootJobID
	reducerTaskParams[taskParamDependencyBackendRunIDs] = append([]string(nil), childBackendRunIDs...)
	return types.SubmitJobRequest{
		TaskType:         reducerTaskType,
		InputRefs:        append([]types.InputRef(nil), req.Reducer.InputRefs...),
		TaskParams:       reducerTaskParams,
		Constraints:      reducerConstraints,
		ExecutionProfile: s.applyExecutionProfileDefaults(reducerProfile),
		OutputSchema:     reducerSchema,
		Orchestration: types.OrchestrationRequest{
			ParentJobID:     req.ParentJobID,
			RootJobID:       rootJobID,
			Strategy:        "aggregator",
			AggregationKey:  firstNonEmpty(req.Reducer.AggregationKey, "aggregate"),
			DependsOnJobIDs: append([]string(nil), orderedChildJobIDs...),
		},
	}
}

func submitCmd(client *http.Client, baseURL string, args []string) {
	fs := flag.NewFlagSet("submit", flag.ExitOnError)
	taskType := fs.String("task-type", "", "Task type, for example document_summary or log_analysis")
	inputURI := fs.String("input-uri", "", "Input file URI, for example file:///tmp/doc.txt")
	schemaName := fs.String("schema", "", "Output schema name")
	classification := fs.String("classification", "", "Optional input classification")
	if err := fs.Parse(args); err != nil {
		os.Exit(2)
	}

	if *taskType == "" || *inputURI == "" || *schemaName == "" {
		fmt.Fprintln(os.Stderr, "submit requires --task-type, --input-uri, and --schema")
		fs.Usage()
		os.Exit(2)
	}

	reqBody := types.SubmitJobRequest{
		TaskType: *taskType,
		InputRefs: []types.InputRef{
			{
				Type: "file",
				URI:  *inputURI,
			},
		},
		OutputSchema: types.OutputSchemaRef{Name: *schemaName},
	}
	if *classification != "" {
		reqBody.TaskParams = map[string]any{
			"classification": *classification,
		}
	}

	payload, err := json.Marshal(reqBody)
	if err != nil {
		fatalf("marshal request: %v", err)
	}

	respBody := doJSON(client, http.MethodPost, strings.TrimRight(baseURL, "/")+"/v1/jobs", payload)
	fmt.Println(respBody)
}

